76	export function claim(
77	  policy: { remainingCap: number; items: { type: string; enchantment?: number }[] },
78	  incident: { damages: { itemType: string; amount: number }[] }
79	): { payout: number; remainingCap: number } {
80	  const damagesByType: Record<string, number> = {};
81	  for (const damage of incident.damages) {
82	    damagesByType[damage.itemType] = (damagesByType[damage.itemType] ?? 0) + 1;
83	  }
84	  const insuredByType: Record<string, number> = {};
85	  for (const item of policy.items) {
86	    insuredByType[item.type] = (insuredByType[item.type] ?? 0) + 1;
87	  }
88	  for (const type of Object.keys(damagesByType)) {
89	    if (damagesByType[type] > (insuredByType[type] ?? 0)) {
90	      throw new Error(`More damages of type ${type} than insured items`);
91	    }
92	  }
93	  let payout = 0;
94	  for (const damage of incident.damages) {
95	    const item = policy.items.find((i) => i.type === damage.itemType);
96	    let amount = damage.amount;
97	    if (item && (item.enchantment ?? 0) >= 8) {
98	      amount = amount * 0.5;
99	    }
100	    payout += Math.max(0, amount - 100);
101	  }
102	  payout = Math.min(payout, policy.remainingCap);
103	  return { payout, remainingCap: policy.remainingCap - payout };
104	}
